26	// Start/resetart zeromq server
27	void RogueTcpMemoryRestart(RogueTcpMemoryData *data, portDataT *portData) {
28	    char buffer[100];
29	
30	    if ( data->zmqPush  != NULL ) zmq_close(data->zmqPull);
31	    if ( data->zmqPull  != NULL ) zmq_close(data->zmqPush);
32	    if ( data->zmqCtx   != NULL ) zmq_term(data->zmqCtx);
33	
34	    data->zmqCtx   = NULL;
35	    data->zmqPull  = NULL;
36	    data->zmqPush  = NULL;
37	
38	    data->zmqCtx = zmq_ctx_new();
39	    data->zmqPull  = zmq_socket(data->zmqCtx, ZMQ_PULL);
40	    data->zmqPush  = zmq_socket(data->zmqCtx, ZMQ_PUSH);
41	
42	    vhpi_printf("RogueTcpMemory: Listening on ports %i & %i\n", data->port, data->port+1);
43	
44	    snprintf(buffer, sizeof(buffer), "tcp://127.0.0.1:%i", data->port);
45	    if ( zmq_bind(data->zmqPull, buffer) ) {
46	        vhpi_assert("RogueTcpMemory: Failed to bind pull port", vhpiFatal);
47	        return;
48	    }
49	
50	    snprintf(buffer, sizeof(buffer), "tcp://127.0.0.1:%i", data->port+1);
51	    if ( zmq_bind(data->zmqPush, buffer) ) {
52	        vhpi_assert("RogueTcpMemory: Failed to bind push port", vhpiFatal);
53	        return;
54	    }
55	}
56	
57	// Send a message
58	void RogueTcpMemorySend(RogueTcpMemoryData *data, portDataT *portData) {
59	    uint32_t  x;
60	    zmq_msg_t msg[6];
61	
62	    if ( (zmq_msg_init_size(&(msg[0]), 4) < 0) ||   // ID
63	        (zmq_msg_init_size(&(msg[1]), 8) < 0) ||   // Addr
64	        (zmq_msg_init_size(&(msg[2]), 4) < 0) ||   // Size
65	        (zmq_msg_init_size(&(msg[3]), 4) < 0) ||   // type
66	        (zmq_msg_init_size(&(msg[5]), 4) < 0) ) {  // result
67	        vhpi_assert("RogueTcpMemory: Failed to init message header", vhpiFatal);
68	        return;
69	    }
70	
71	    if (zmq_msg_init_size(&(msg[4]), data->size) < 0) {
72	        vhpi_assert("RogueTcpMemory: Failed to init message", vhpiFatal);
73	        return;
74	    }
75	
76	    memcpy(zmq_msg_data(&(msg[0])), &(data->id),     4);
77	    memcpy(zmq_msg_data(&(msg[1])), &(data->addr),   8);
78	    memcpy(zmq_msg_data(&(msg[2])), &(data->size),   4);
79	    memcpy(zmq_msg_data(&(msg[3])), &(data->type),   4);
80	    memcpy(zmq_msg_data(&(msg[5])), &(data->result), 4);
81	
82	    // Copy data
83	    memcpy(zmq_msg_data(&(msg[4])), data->data, data->size);
84	
85	    // Send data
86	    for (x=0; x < 6; x++) {
87	        if ( zmq_sendmsg(data->zmqPush, &(msg[x]), (x == 5)?0:ZMQ_SNDMORE) < 0 )
88	            vhpi_assert("RogueTcpMemory: Failed to send message", vhpiFatal);
89	    }
90	    data->state = 0;
91	    data->curr  = 0;
92	
93	    vhpi_printf("%lu RogueTcpMemory: Send Tran: Id %i, Addr 0x%x, Size %i, Type %i, Resp 0x%x\n", portData->simTime, data->id, data->addr, data->size, data->type, data->result);
94	}
95	
96	// Receive data if it is available
97	int RogueTcpMemoryRecv(RogueTcpMemoryData *data, portDataT *portData) {
98	    uint64_t  more;
99	    size_t    moreSize;
100	    uint32_t  x;
101	    uint32_t  msgCnt;
102	    zmq_msg_t msg[5];
103	
104	    for (x=0; x < 5; x++) zmq_msg_init(&(msg[x]));
105	    msgCnt = 0;
106	    x = 0;
107	
108	    // Get message
109	    do {
110	        // Get the message
111	        if (zmq_recvmsg(data->zmqPull, &(msg[x]), ZMQ_DONTWAIT) > 0) {
112	            if ( x != 4 ) x++;
113	            msgCnt++;
114	
115	            // Is there more data?
116	            more = 0;
117	            moreSize = 8;
118	            zmq_getsockopt(data->zmqPull, ZMQ_RCVMORE, &more, &moreSize);
119	        } else {
120	            more = 0;
121	        }
122	    } while ( more );
123	
124	    // Proper message received
125	    if (msgCnt == 4 || msgCnt == 5) {
126	        // Check sizes
127	        if ( (zmq_msg_size(&(msg[0])) != 4) || (zmq_msg_size(&(msg[1])) != 8) ||
128	             (zmq_msg_size(&(msg[2])) != 4) || (zmq_msg_size(&(msg[3])) != 4) ) {
129	            vhpi_assert("RogueTcpMemory: Bad message size", vhpiFatal);
130	            for (x=0; x < msgCnt; x++) zmq_msg_close(&(msg[x]));
131	            return 0;
132	        }
133	
134	        // Get fields
135	        memcpy(&(data->id),   zmq_msg_data(&(msg[0])), 4);
136	        memcpy(&(data->addr), zmq_msg_data(&(msg[1])), 8);
137	        memcpy(&(data->size), zmq_msg_data(&(msg[2])), 4);
138	        memcpy(&(data->type), zmq_msg_data(&(msg[3])), 4);
139	
140	        // Write data is expected
141	        if ( (data->type == T_WRITE) || (data->type == T_POST) ) {
142	            if ( (msgCnt != 5) || (zmq_msg_size(&(msg[4])) != data->size) ) {
143	                vhpi_assert("RogueTcpMemory: Transaction write data error", vhpiFatal);
144	                for (x=0; x < msgCnt; x++) zmq_msg_close(&(msg[x]));
145	                    return 0;
146	            }
147	        }
148	
149	        // Data pointer
150	        memcpy(data->data, zmq_msg_data(&(msg[4])), data->size);
151	        data->state  = ST_START;
152	        data->curr   = 0;
153	        data->result = 0;
154	
155	        vhpi_printf("%lu RogueTcpMemory: Got Tran: Id %i, Addr 0x%x, Size %i, Type %i\n", portData->simTime, data->id, data->addr, data->size, data->type);
156	
157	        return(data->size);
158	    }
159	    return (0);
160	}
