162	// Init function
163	void RogueTcpMemoryInit(vhpiHandleT compInst) {
164	    // Create new port data structure
165	    portDataT             *portData  = (portDataT *)             malloc(sizeof(portDataT));
166	    RogueTcpMemoryData *data      = (RogueTcpMemoryData *) malloc(sizeof(RogueTcpMemoryData));
167	
168	    // Get port count
169	    portData->portCount = PORT_COUNT;
170	
171	    // Set port directions
172	    portData->portDir[s_clock]      = vhpiIn;
173	    portData->portDir[s_reset]      = vhpiIn;
174	    portData->portDir[s_port]       = vhpiIn;
175	
176	    portData->portDir[s_araddr]     = vhpiOut;
177	    portData->portDir[s_arprot]     = vhpiOut;
178	    portData->portDir[s_arvalid]    = vhpiOut;
179	    portData->portDir[s_rready]     = vhpiOut;
180	
181	    portData->portDir[s_arready]    = vhpiIn;
182	    portData->portDir[s_rdata]      = vhpiIn;
183	    portData->portDir[s_rresp]      = vhpiIn;
184	    portData->portDir[s_rvalid]     = vhpiIn;
185	
186	    portData->portDir[s_awaddr]     = vhpiOut;
187	    portData->portDir[s_awprot]     = vhpiOut;
188	    portData->portDir[s_awvalid]    = vhpiOut;
189	    portData->portDir[s_wdata]      = vhpiOut;
190	    portData->portDir[s_wstrb]      = vhpiOut;
191	    portData->portDir[s_wvalid]     = vhpiOut;
192	    portData->portDir[s_bready]     = vhpiOut;
193	
194	    portData->portDir[s_awready]    = vhpiIn;
195	    portData->portDir[s_wready]     = vhpiIn;
196	    portData->portDir[s_bresp]      = vhpiIn;
197	    portData->portDir[s_bvalid]     = vhpiIn;
198	
199	    // Set port widths
200	    portData->portWidth[s_clock]    = 1;
201	    portData->portWidth[s_reset]    = 1;
202	    portData->portWidth[s_port]     = 16;
203	
204	    portData->portWidth[s_araddr]   = 32;
205	    portData->portWidth[s_arprot]   = 3;
206	    portData->portWidth[s_arvalid]  = 1;
207	    portData->portWidth[s_rready]   = 1;
208	
209	    portData->portWidth[s_arready]  = 1;
210	    portData->portWidth[s_rdata]    = 32;
211	    portData->portWidth[s_rresp]    = 2;
212	    portData->portWidth[s_rvalid]   = 1;
213	
214	    portData->portWidth[s_awaddr]   = 32;
215	    portData->portWidth[s_awprot]   = 3;
216	    portData->portWidth[s_awvalid]  = 1;
217	    portData->portWidth[s_wdata]    = 32;
218	    portData->portWidth[s_wstrb]    = 4;
219	    portData->portWidth[s_wvalid]   = 1;
220	    portData->portWidth[s_bready]   = 1;
221	
222	    portData->portWidth[s_awready]  = 1;
223	    portData->portWidth[s_wready]   = 1;
224	    portData->portWidth[s_bresp]    = 2;
225	    portData->portWidth[s_bvalid]   = 1;
226	
227	    // Create data structure to hold state
228	    portData->stateData = data;
229	
230	    // State update function
231	    portData->stateUpdate = *RogueTcpMemoryUpdate;
232	
233	    // Init
234	    memset(data, 0, sizeof(RogueTcpMemoryData));
235	
236	    // Call generic Init
237	    VhpiGenericInit(compInst, portData);
238	}
239	
240	
241	// User function to update state based upon a signal change
242	void RogueTcpMemoryUpdate(void *userPtr) {
243	    uint32_t data32;
244	
245	    portDataT *portData = (portDataT*) userPtr;
246	    RogueTcpMemoryData *data = (RogueTcpMemoryData*)(portData->stateData);
247	
248	    // Detect clock edge
249	    if ( data->currClk != getInt(s_clock) ) {
250	        data->currClk = getInt(s_clock);
251	
252	        // Rising edge
253	        if ( data->currClk ) {
254	            // Reset is asserted
255	            if ( getInt(s_reset) == 1 ) {
256	                data->state = ST_IDLE;
257	                setInt(s_arvalid, 0);
258	                setInt(s_rready, 1);
259	                setInt(s_awvalid, 0);
260	                setInt(s_bready, 1);
261	
262	            // Data movement
263	            } else {
264	                // Port not yet assigned
265	                if ( data->port == 0 ) {
266	                    data->port = getInt(s_port);
267	                    RogueTcpMemoryRestart(data, portData);
268	                }
269	
270	                switch (data->state) {
271	                    // Idle get new data
272	                    case ST_IDLE:
273	                        RogueTcpMemoryRecv(data, portData);
274	                        break;
275	
276	                    // Start, present transaction
277	                    case ST_START:
278	
279	                        // Write
280	                        if ( data->type == T_WRITE || data->type == T_POST ) {
281	                            setInt(s_awaddr, (data->addr+data->curr));
282	                            setInt(s_awprot, 0);
283	                            setInt(s_awvalid, 1);
284	                            setInt(s_bready, 1);
285	
286	                            data32  = data->data[data->curr++]         & 0x000000FF;
287	                            data32 |= (data->data[data->curr++] <<  8) & 0x0000FF00;
288	                            data32 |= (data->data[data->curr++] << 16) & 0x00FF0000;
289	                            data32 |= (data->data[data->curr++] << 24) & 0xFF000000;
290	
291	                            setInt(s_wdata, data32);
292	                            setInt(s_wstrb, 0xF);
293	                            setInt(s_wvalid, 1);
294	                            data->state = ST_WRESP;
295	
296	                        // Read
297	                        } else {
298	                            setInt(s_araddr, (data->addr+data->curr));
299	                            setInt(s_arprot, 0);
300	                            setInt(s_arvalid, 1);
301	                            setInt(s_rready, 1);
302	                            data->state = ST_RADDR;
303	                        }
304	                        break;
305	
306	                    // Write response
307	                    case ST_WRESP:
308	
309	                        if ( getInt(s_awready) ) setInt(s_awvalid, 0);
310	                        if ( getInt(s_wready)  ) setInt(s_wvalid, 0);
311	
312	                        if ( getInt(s_bvalid) ) {
313	                            // setInt(s_bready,0);
314	                            data->result = getInt(s_bresp);
315	
316	                            if (data->curr == data->size) {
317	                                RogueTcpMemorySend(data, portData);  // state goes to idle
318	                            } else {
319	                                data->state = ST_PAUSE;
320	                            }
321	                        }
322	                        break;
323	
324	                    // Read address
325	                    case ST_RADDR:
326	                        if ( getInt(s_arready) ) {
327	                            setInt(s_arvalid, 0);
328	                            setInt(s_rready, 1);
329	                            data->state = ST_RDATA;
330	                        }
331	                        break;
332	
333	                    // Read data
334	                    case ST_RDATA:
335	                        if ( getInt(s_rvalid) ) {
336	                            data32 = getInt(s_rdata);
337	                            data->result = getInt(s_rresp);
338	
339	                            data->data[data->curr++] = data32 & 0xFF;
340	                            data->data[data->curr++] = (data32 >>  8) & 0xFF;
341	                            data->data[data->curr++] = (data32 >> 16) & 0xFF;
342	                            data->data[data->curr++] = (data32 >> 24) & 0xFF;
343	
344	                            // setInt(s_rready,0);
345	
346	                            if (data->curr == data->size) {
347	                                RogueTcpMemorySend(data, portData);  // state goes to idle
348	                            } else {
349	                                data->state = ST_PAUSE;
350	                            }
351	                        }
352	                        break;
353	
354	                    // Wait for RVALID and BVALID to fall
355	                    case ST_PAUSE:
356	                        if ( getInt(s_rvalid) == 0 && getInt(s_bvalid) == 0 ) {
357	                            data->state = ST_START;
358	                            break;
359	                        }
360	                }
361	            }
362	        }
363	    }
364	}
