#define s_ibReady      13
#define s_ibDataLow    14
#define s_ibDataHigh   15
#define s_ibUserLow    16
#define s_ibUserHigh   17
#define s_ibKeep       18
#define s_ibLast       19

#define PORT_COUNT     20

#define MAX_FRAME 20000000

// Structure to track state
typedef struct {
    uint8_t   obFuser;
    uint8_t   obLuser;
    uint32_t  obSize;
    uint32_t  obCount;
    uint8_t   obData[MAX_FRAME];
    uint32_t  obValid;

    uint8_t   ibFuser;
    uint8_t   ibLuser;
    uint32_t  ibSize;
    uint8_t   ibData[MAX_FRAME];

    uint32_t  currClk;
    uint16_t  port;
    uint8_t   ssi;
    time_t    ltime;

    void *    zmqCtx;
    void *    zmqPush;
    void *    zmqPull;
} RogueTcpStreamData;

