23	
24	#include "VhpiGeneric.h"
25	#include "RogueTcpStream.h"
26	
27	// Start/resetart zeromq server
28	void RogueTcpStreamRestart(RogueTcpStreamData *data, portDataT *portData) {
29	    char buffer[100];
30	
31	    if ( data->zmqPush != NULL ) zmq_close(data->zmqPush );
32	    if ( data->zmqPull != NULL ) zmq_close(data->zmqPull );
33	    if ( data->zmqCtx  != NULL ) zmq_term(data->zmqCtx);
34	
35	    data->zmqCtx   = NULL;
36	    data->zmqPush  = NULL;
37	    data->zmqPull  = NULL;
38	
39	    data->zmqCtx = zmq_ctx_new();
40	    data->zmqPull  = zmq_socket(data->zmqCtx, ZMQ_PULL);
41	    data->zmqPush  = zmq_socket(data->zmqCtx, ZMQ_PUSH);
42	
43	    vhpi_printf("RogueTcpStream: Listening on ports %i & %i\n", data->port, data->port+1);
44	
45	    snprintf(buffer, sizeof(buffer), "tcp://127.0.0.1:%i", data->port);
46	    if ( zmq_bind(data->zmqPull, buffer) ) {
47	        vhpi_assert("RogueTcpStream: Failed to bind pull port", vhpiFatal);
48	        return;
49	    }
50	
51	    snprintf(buffer, sizeof(buffer), "tcp://127.0.0.1:%i", data->port+1);
52	    if ( zmq_bind(data->zmqPush, buffer) ) {
53	        vhpi_assert("RogueTcpStream: Failed to bind push port", vhpiFatal);
54	        return;
55	    }
56	}
57	
58	// Send a message
59	void RogueTcpStreamSend(RogueTcpStreamData *data, portDataT *portData) {
60	    zmq_msg_t msg[4];
61	    uint16_t  flags;
62	    uint8_t   chan;
63	    uint8_t   err;
64	    uint32_t  x;
65	    int error;
66	
67	    if ( (zmq_msg_init_size(&(msg[0]), 2) < 0) ||   // Flags
68	         (zmq_msg_init_size(&(msg[1]), 1) < 0) ||   // Channel
69	         (zmq_msg_init_size(&(msg[2]), 1) < 0) ) {  // Error
70	        vhpi_assert("RogueTcpStream: Failed to init message header", vhpiFatal);
71	        return;
72	    }
73	
74	    if (zmq_msg_init_size(&(msg[3]), data->ibSize) < 0) {
75	        vhpi_assert("RogueTcpStream: Failed to init message", vhpiFatal);
76	        return;
77	    }
78	
79	    if ( data->ssi ) {
80	        flags  = (data->ibFuser & 0xFF);
81	        flags |= ((data->ibLuser << 8) & 0xFF00);
82	        err    = data->ibLuser & 0x1;
83	    } else {
84	        flags = 0;
85	        err   = 0;
86	    }
87	    chan = 0;
88	
89	    memcpy(zmq_msg_data(&(msg[0])), &flags, 2);
90	    memcpy(zmq_msg_data(&(msg[1])), &chan,  1);
91	    memcpy(zmq_msg_data(&(msg[2])), &err,   1);
92	
93	    // Copy data
94	    memcpy(zmq_msg_data(&(msg[3])), data->ibData, data->ibSize);
95	
96	    // Send data
97	    for (x=0; x < 4; x++) {
98	        if ( zmq_msg_send(&(msg[x]), data->zmqPush, (x == 3)?0:ZMQ_SNDMORE) < 0 ) {
99	            error = errno;
100	            vhpi_printf("Failed to send message on port %i - x: %i - err: %i\n", data->port+1, x, error);
101	            vhpi_printf("Error: %s\n", strerror(error));
102	            vhpi_assert("RogueTcpStream: Failed to send message", vhpiFatal);
103	        }
104	    }
105	    vhpi_printf("%lu RogueTcpStream: Send data: Size: %i, flags: %x, chan: %x, err: %x, port: %i\n", portData->simTime, data->ibSize, flags, chan, err, data->port+1);
106	    data->ibSize = 0;
107	}
108	
109	// Receive data if it is available
110	int RogueTcpStreamRecv(RogueTcpStreamData *data, portDataT *portData) {
111	    int64_t   more;
112	    size_t    moreSize;
113	    uint32_t  size;
114	    zmq_msg_t msg[4];
115	    uint32_t  msgCnt;
116	    uint16_t  flags;
117	    uint8_t   chan;
118	    uint8_t   err;
119	    uint32_t  x;
120	
121	    for (x=0; x < 4; x++) zmq_msg_init(&(msg[x]));
122	    msgCnt = 0;
123	    x = 0;
124	
125	    // Get message
126	    do {
127	        // Get the message
128	        if ( zmq_recvmsg(data->zmqPull, &(msg[x]), ZMQ_DONTWAIT) > 0 ) {
129	            if ( x != 3 ) x++;
130	            msgCnt++;
131	
132	            // Is there more data?
133	            more = 0;
134	            moreSize = 8;
135	            zmq_getsockopt(data->zmqPull, ZMQ_RCVMORE, &more, &moreSize);
136	        } else {
137	            more = 0;
138	        }
139	    } while ( more );
140	
141	    // Proper message received
142	    if ( msgCnt == 4 ) {
143	        // Check sizes
144	        if ( (zmq_msg_size(&(msg[0])) != 2) || (zmq_msg_size(&(msg[1])) != 1) || (zmq_msg_size(&(msg[2])) != 1) ) {
145	            vhpi_assert("RogueTcpStream: Bad message sizes", vhpiFatal);
146	            for (x=0; x < msgCnt; x++) zmq_msg_close(&(msg[x]));
147	            return 0;
148	        }
149	
150	        // Get fields
151	        memcpy(&flags, zmq_msg_data(&(msg[0])), 2);
152	        memcpy(&chan,  zmq_msg_data(&(msg[1])), 1);
153	        memcpy(&err,   zmq_msg_data(&(msg[2])), 1);
154	
155	        // Get message info
156	        size = zmq_msg_size(&(msg[3]));
157	
158	        // Set data
159	        memcpy(data->obData, zmq_msg_data(&(msg[3])), size);
160	        data->obSize  = size;
161	        data->obFuser = flags & 0xFF;
162	        data->obLuser = (flags >> 8) & 0xFF;
163	
164	        if ( data->ssi ) {
165	            data->obFuser |= 0x02;
166	            if ( err ) data->obLuser |= 0x01;
167	        }
168	
169	        vhpi_printf("%lu RogueTcpStream: Recv data: Size: %i, flags: %x, chan: %i, err: %i, port: %i\n", portData->simTime, data->obSize, flags, chan, err, data->port);
170	
171	    } else {
172	        size = 0;
173	    }
174	
175	    for (x=0; x < 4; x++) zmq_msg_close(&(msg[x]));
176	
177	    return(size);
178	}
179	
180	// Init function
181	void RogueTcpStreamInit(vhpiHandleT compInst) {
182	    // Create new port data structure
183	    portDataT             *portData  = (portDataT *)             malloc(sizeof(portDataT));
184	    RogueTcpStreamData *data      = (RogueTcpStreamData *) malloc(sizeof(RogueTcpStreamData));
185	
186	    // Get port count
187	    portData->portCount = PORT_COUNT;
188	
189	    // Set port directions
190	    portData->portDir[s_clock]      = vhpiIn;
191	    portData->portDir[s_reset]      = vhpiIn;
192	    portData->portDir[s_port]       = vhpiIn;
193	    portData->portDir[s_ssi]        = vhpiIn;
194	
195	    portData->portDir[s_obValid]    = vhpiOut;
196	    portData->portDir[s_obReady]    = vhpiIn;
197	    portData->portDir[s_obDataLow]  = vhpiOut;
198	    portData->portDir[s_obDataHigh] = vhpiOut;
199	    portData->portDir[s_obUserLow]  = vhpiOut;
200	    portData->portDir[s_obUserHigh] = vhpiOut;
201	    portData->portDir[s_obKeep]     = vhpiOut;
202	    portData->portDir[s_obLast]     = vhpiOut;
203	
204	    portData->portDir[s_ibValid]    = vhpiIn;
205	    portData->portDir[s_ibReady]    = vhpiOut;
206	    portData->portDir[s_ibDataLow]  = vhpiIn;
207	    portData->portDir[s_ibDataHigh] = vhpiIn;
208	    portData->portDir[s_ibUserLow]  = vhpiIn;
209	    portData->portDir[s_ibUserHigh] = vhpiIn;
210	    portData->portDir[s_ibKeep]     = vhpiIn;
211	    portData->portDir[s_ibLast]     = vhpiIn;
212	
213	    // Set port widths
214	    portData->portWidth[s_clock]      = 1;
215	    portData->portWidth[s_reset]      = 1;
216	    portData->portWidth[s_port]       = 16;
217	    portData->portWidth[s_ssi]        = 1;
218	
219	    portData->portWidth[s_obValid]    = 1;
220	    portData->portWidth[s_obReady]    = 1;
221	    portData->portWidth[s_obDataLow]  = 32;
222	    portData->portWidth[s_obDataHigh] = 32;
223	    portData->portWidth[s_obUserLow]  = 32;
224	    portData->portWidth[s_obUserHigh] = 32;
225	    portData->portWidth[s_obKeep]     = 8;
226	    portData->portWidth[s_obLast]     = 1;
227	
228	    portData->portWidth[s_ibValid]    = 1;
229	    portData->portWidth[s_ibReady]    = 1;
230	    portData->portWidth[s_ibDataLow]  = 32;
231	    portData->portWidth[s_ibDataHigh] = 32;
232	    portData->portWidth[s_ibUserLow]  = 32;
233	    portData->portWidth[s_ibUserHigh] = 32;
234	    portData->portWidth[s_ibKeep]     = 8;
235	    portData->portWidth[s_ibLast]     = 1;
236	
237	    // Create data structure to hold state
238	    portData->stateData = data;
239	
240	    // State update function
241	    portData->stateUpdate = *RogueTcpStreamUpdate;
242	
243	    // Init
244	    memset(data, 0, sizeof(RogueTcpStreamData));
245	    time(&(data->ltime));
246	
247	    // Call generic Init
248	    VhpiGenericInit(compInst, portData);
249	}
250	
251	// User function to update state based upon a signal change
252	void RogueTcpStreamUpdate(void *userPtr) {
253	    uint32_t x;
254	    uint32_t keep;
255	    uint32_t dLow;
256	    uint32_t dHigh;
257	    uint32_t uLow;
258	    uint32_t uHigh;
259	
260	    portDataT *portData = (portDataT*) userPtr;
261	    RogueTcpStreamData *data = (RogueTcpStreamData*)(portData->stateData);
262	
263	    // Detect clock edge
264	    if ( data->currClk != getInt(s_clock) ) {
265	        data->currClk = getInt(s_clock);
266	
267	        // Rising edge
268	        if ( data->currClk ) {
269	            // Reset is asserted
270	            if ( getInt(s_reset) == 1 ) {
271	                data->obCount = 0;
272	                data->obSize  = 0;
273	                data->ibSize  = 0;
274	                data->obValid = 0;
275	                setInt(s_obValid, 0);
276	                setInt(s_ibReady, 1);
277	                setInt(s_obDataLow, 0);
278	                setInt(s_obDataHigh, 0);
279	                setInt(s_obUserLow, 0);
280	                setInt(s_obUserHigh, 0);
281	                setInt(s_obKeep, 0);
282	                setInt(s_obLast, 0);
283	
284	            // Data movement
285	            } else {
286	                // Port not yet assigned
287	                if ( data->port == 0 ) {
288	                    data->port = getInt(s_port);
289	                    data->ssi  = getInt(s_ssi);
290	                    RogueTcpStreamRestart(data, portData);
291	                }
292	
293	                // Inbound
294	                if (getInt(s_ibValid)) {
295	                    keep  = getInt(s_ibKeep);
296	                    dLow  = getInt(s_ibDataLow);
297	                    dHigh = getInt(s_ibDataHigh);
298	                    uLow  = getInt(s_ibUserLow);
299	                    uHigh = getInt(s_ibUserHigh);
300	
301	                    // First
302	                    if ( data->ibSize == 0 ) data->ibFuser = uLow & 0xFF;
303	
304	                    // Get data
305	                    for (x=0; x< 8; x++) {
306	                        if ( x < 4 ) {
307	                            data->ibData[data->ibSize] = (dLow >> (x*8)) & 0xFF;
308	                            if ( (keep >> x) && 1 ) data->ibLuser = (uLow >> (x*8)) & 0xFF;
309	                        } else {
310	                            data->ibData[data->ibSize] = (dHigh >> ((x-4)*8)) & 0xFF;
311	                            if ( (keep >> x) && 1 ) data->ibLuser = (uHigh >> ((x-4)*8)) & 0xFF;
312	                        }
313	                        if ( (keep >> x) && 1 ) data->ibSize++;
314	                    }
315	
316	                    // Last
317	                    if ( getInt(s_ibLast) ) RogueTcpStreamSend(data, portData);
318	                }
319	
320	                // Not in frame
321	                if ( data->obSize == 0 ) RogueTcpStreamRecv(data, portData);
322	
323	                // Data accepted
324	                if ( getInt(s_obReady) ) {
325	                    data->obValid = 0;
326	                    setInt(s_obLast, 0);
327	                }
328	
329	                // Valid not asserted and data is ready
330	                if ( data->obValid == 0 && data->obSize > 0 ) {
331	                    // First user
332	                    if ( data->obCount == 0 ) {
333	                        setInt(s_obUserLow, data->obFuser);
334	                    } else {
335	                        setInt(s_obUserLow, 0);
336	                    }
337	                    setInt(s_obUserHigh, 0);
338	
339	                    // Get data
340	                    dHigh = 0;
341	                    dLow  = 0;
342	                    keep  = 0;
343	
344	                    // Set data
345	                    for (x=0; x< 8; x++) {
346	                        if ( x < 4 ) {
347	                            dLow |= (data->obData[data->obCount] << (x*8));
348	                            if ( (data->obCount+1) == data->obSize ) {
349	                                if (data->obCount < 4) {
350	                                    setInt(s_obUserLow, (data->obLuser << (x*8))|(data->obFuser));
351	                                } else {
352	                                    setInt(s_obUserLow, (data->obLuser << (x*8)));
353	                                }
354	                            }
355	                        } else {
356	                            dHigh |= (data->obData[data->obCount] << ((x-4)*8));
357	                            if ( (data->obCount+1) == data->obSize )
358	                                setInt(s_obUserHigh, (data->obLuser << ((x-4)*8)));
359	                        }
360	
361	                        data->obCount++;
362	                        if ( data->obCount <= data->obSize ) keep |= (1 << x);
363	                    }
364	                    setInt(s_obDataLow, dLow);
365	                    setInt(s_obDataHigh, dHigh);
366	                    setInt(s_obKeep, keep);
367	                    data->obValid = 1;
368	
369	                    // Done
370	                    if ( data->obCount >= data->obSize ) {
371	                        setInt(s_obLast, 1);
372	                        data->obSize  = 0;
373	                        data->obCount = 0;
374	                    }
375	                }
376	
377	                // Output valid
378	                setInt(s_obValid, data->obValid);
379	            }
380	        }
381	    }
382	}
