33	      NUM_VC_G      : integer range 1 to 16       := 4;
34	      EN_SIDEBAND_G : boolean                     := true);
35	   port (
36	      -- GT Ports
37	      pgpRefClk       : in  sl;
38	      pgpGtRxP        : in  sl;
39	      pgpGtRxN        : in  sl;
40	      pgpGtTxP        : out sl                     := '0';
41	      pgpGtTxN        : out sl                     := '1';
42	      -- PGP Clock and Reset
43	      pgpClk          : out sl;
44	      pgpClkRst       : out sl;
45	      -- Non VC Rx Signals
46	      pgpRxIn         : in  Pgp3RxInType;
47	      pgpRxOut        : out Pgp3RxOutType;
48	      -- Non VC Tx Signals
49	      pgpTxIn         : in  Pgp3TxInType;
50	      pgpTxOut        : out Pgp3TxOutType;
51	      -- Frame Transmit Interface
52	      pgpTxMasters    : in  AxiStreamMasterArray(NUM_VC_G-1 downto 0);
53	      pgpTxSlaves     : out AxiStreamSlaveArray(NUM_VC_G-1 downto 0);
54	      -- Frame Receive Interface
55	      pgpRxMasters    : out AxiStreamMasterArray(NUM_VC_G-1 downto 0);
56	      pgpRxSlaves     : in  AxiStreamSlaveArray(NUM_VC_G-1 downto 0);
57	      -- AXI-Lite Register Interface (axilClk domain)
58	      axilClk         : in  sl                     := '0';  -- Stable Clock
59	      axilRst         : in  sl                     := '0';
60	      axilReadMaster  : in  AxiLiteReadMasterType  := AXI_LITE_READ_MASTER_INIT_C;
61	      axilReadSlave   : out AxiLiteReadSlaveType   := AXI_LITE_READ_SLAVE_EMPTY_OK_C;
62	      axilWriteMaster : in  AxiLiteWriteMasterType := AXI_LITE_WRITE_MASTER_INIT_C;
63	      axilWriteSlave  : out AxiLiteWriteSlaveType  := AXI_LITE_WRITE_SLAVE_EMPTY_OK_C);
64	end entity RoguePgp3Sim;
65	
66	architecture sim of RoguePgp3Sim is
67	
68	   signal clk : sl := '0';
69	   signal rst : sl := '1';
70	
71	   signal txOut : Pgp3TxOutType := PGP3_TX_OUT_INIT_C;
72	   signal rxOut : Pgp3RxOutType := PGP3_RX_OUT_INIT_C;
73	
74	begin
75	
76	   pgpClk    <= clk;
77	   pgpClkRst <= rst;
78	
79	   pgpTxOut <= txOut;
80	   pgpRxOut <= rxOut;
81	
82	   clk <= pgpRefClk;
83	
84	   PwrUpRst_Inst : entity surf.PwrUpRst
85	      generic map (
86	         TPD_G          => TPD_G,
87	         IN_POLARITY_G  => '1',
88	         OUT_POLARITY_G => '1',
89	         DURATION_G     => 50)
90	      port map (
91	         clk    => clk,
92	         rstOut => rst);
93	
94	   GEN_VEC : for i in NUM_VC_G-1 downto 0 generate
95	      U_PGP_VC : entity surf.RogueTcpStreamWrap
96	         generic map (
97	            TPD_G         => TPD_G,
98	            PORT_NUM_G    => (PORT_NUM_G + i*2),
99	            SSI_EN_G      => true,
100	            CHAN_COUNT_G  => 1,
101	            TDEST_MASK_G  => toSlv(i, 8),
102	            AXIS_CONFIG_G => PGP3_AXIS_CONFIG_C)
103	         port map (
104	            axisClk     => clk,              -- [in]
105	            axisRst     => rst,              -- [in]
106	            sAxisMaster => pgpTxMasters(i),  -- [in]
107	            sAxisSlave  => pgpTxSlaves(i),   -- [out]
108	            mAxisMaster => pgpRxMasters(i),  -- [out]
109	            mAxisSlave  => pgpRxSlaves(i));  -- [in]
110	   end generate GEN_VEC;
111	
112	   GEN_SIDEBAND : if (EN_SIDEBAND_G) generate
113	      U_RogueSideBandWrap_1 : entity surf.RogueSideBandWrap
114	         generic map (
115	            TPD_G      => TPD_G,
116	            PORT_NUM_G => PORT_NUM_G + 32)
117	         port map (
118	            sysClk     => clk,
119	            sysRst     => rst,
120	            txOpCode   => pgpTxIn.opCodeData(7 downto 0),
121	            txOpCodeEn => pgpTxIn.opCodeEn,
122	            txRemData  => pgpTxIn.opCodeData(15 downto 8),
123	            rxOpCode   => rxOut.opCodeData(7 downto 0),
124	            rxOpCodeEn => rxOut.opCodeEn,
125	            rxRemData  => rxOut.opCodeData(15 downto 8));
126	   end generate GEN_SIDEBAND;
127	
128	   txOut.phyTxActive <= '1';
129	   txOut.linkReady   <= '1';
130	
131	   rxOut.phyRxActive    <= '1';
132	   rxOut.linkReady      <= '1';
133	   rxOut.remRxLinkReady <= '1';
134	
135	end sim;
